from collections import deque

class Solution:
    def wordBreak(self, s: str, wordDict) -> bool:
        word_set = set(wordDict)
        n = len(s)
        visited = [False] * (n + 1)
        queue = deque([0])
        visited[0] = True
        while queue:
            start = queue.popleft()
            for end in range(start + 1, n + 1):
                if visited[end]:
                    continue
                if s[start:end] in word_set:
                    if end == n:
                        return True
                    visited[end] = True
                    queue.append(end)
        return False
